      ]
    },
    "lower_left_portraits": {
      "position": "lower left",
      "count": 1,
      "description": "larger cropped bust portrait with bob hair and blue dress, speech bubble reading 風が気持ちいいな〜, small leaf doodle nearby"
    },
    "bottom_expression_set": {
      "position": "bottom band",
      "count": 10,
      "labels": [
        "にっこり",
        "てれっ♡",
        "びっくり！",
        "えへへ〜♡",
        "はずかしい…",
        "ぷんっ",
        "ぷく",
        "わーい！",
        "がんばる！",
        "うーん…"
